parameters.jsCode:
// Node: "Rank KB Snippets" — lightweight keyword retrieval (RAG bonus).
// Scores each KnowledgeBase article by token overlap with the ticket's
// summary + description (BM25-lite: rare ticket tokens weigh via idf-ish
// dampening is overkill at this scale; simple overlap with length norm works).
// Top 3 snippets are injected into Prompt 2's ragContext.
const ticket = $('Airtable - Get Ticket').first().json;
const tf = ticket.fields || {};
const queryText = [tf['Issue Summary'], tf['Detailed Description'], tf['Category']].join(' ');

function tokens(s) {
  return String(s || '').toLowerCase().replace(/[^a-z0-9\s]/g, ' ').split(/\s+/).filter(w => w.length > 3);
}
const qSet = new Set(tokens(queryText));

const articles = $input.all().map(i => i.json).filter(j => j && j.fields && j.fields['Content']);
const scored = articles.map(a => {
  const docTokens = tokens(a.fields['Article Title'] + ' ' + a.fields['Content'] + ' ' + (a.fields['Tags'] || []).join(' '));
  let hits = 0;
  const seen = new Set();
  for (const t of docTokens) {
    if (qSet.has(t) && !seen.has(t)) { hits++; seen.add(t); }
  }
  return { article: a, score: qSet.size ? hits / qSet.size : 0 };
}).filter(s => s.score > 0.05)
  .sort((x, y) => y.score - x.score)
  .slice(0, 3);

const ragContext = scored.length
  ? scored.map(s => `[${s.article.fields['Article Title']}]\n${String(s.article.fields['Content']).slice(0, 800)}`).join('\n\n---\n\n')
  : '(no relevant knowledge base articles found)';

return [{ json: {
  record_id: ticket.id,
  ticket_id: tf['Ticket ID'] || ticket.id,
  category: tf['Category'] || 'General Inquiry',
  priority: tf['Priority'] || 'Medium',
  detailed_description: tf['Detailed Description'] || tf['Issue Summary'] || '',
  ragContext,
  kb_articles_used: scored.map(s => s.article.fields['Article Title']),
}}];

parameters.jsonBody:
={{ JSON.stringify({
  model: 'claude-sonnet-5',
  max_tokens: 500,
  temperature: 0.3,
  system: "You are a customer support assistant drafting a suggested reply for a human agent to review and edit before sending. Be empathetic, concise, and specific to the customer's issue. Do not promise resolutions or timelines you cannot verify. Return plain text only (no JSON).",
  messages: [
    {
      role: 'user',
      content: 'Ticket Category: ' + $json.category + '\nPriority: ' + $json.priority + '\nCustomer Issue: ' + $json.detailed_description + '\nRelevant Knowledge Base Snippets (if any):\n"""\n' + $json.ragContext + '\n"""\n\nDraft a suggested reply (max 150 words).'
    }
  ]
}) }}

